      width: 600px;
      height: 100px;
      margin-top: 10px;
    }
    button#export {
      margin-bottom: 10px;
    }
  </style>
</head>
<body>
  <table id="spreadsheet">
    <thead>
      <tr><th></th><th>A</th><th>B</th><th>C</th><th>D</th><th>E</th><th>F</th><th>G</th><th>H</th><th>I</th><th>J</th></tr>
    </thead>
    <tbody>
      <!-- Rows 1-10 -->
    </tbody>
  </table>
  <button id="export">Export CSV</button>
  <textarea id="csv"></textarea>

  <script>
    document.addEventListener('DOMContentLoaded', () => {
      const tbody = document.querySelector('#spreadsheet tbody');
      for (let row = 1; row <= 10; row++) {
        const tr = document.createElement('tr');
        const th = document.createElement('th');
        th.textContent = row;
        tr.appendChild(th);
        for (let col of 'ABCDEFGHIJ') {
          const td = document.createElement('td');
          const input = document.createElement('input');
          input.type = 'text';
          input.id = `cell-${col}${row}`;
          td.appendChild(input);
          tr.appendChild(td);
        }
        tbody.appendChild(tr);
      }

      const cells = {};
      for (let col of 'ABCDEFGHIJ') {
        for (let row = 1; row <= 10; row++) {
          const id = `${col}${row}`;
          cells[id] = { raw: '', value: null, displayValue: '' };
        }
      }

      const dependencyGraph = {};
      for (let col of 'ABCDEFGHIJ') {
        for (let row = 1; row <= 10; row++) {
          const id = `${col}${row}`;
          dependencyGraph[id] = { dependencies: [], dependents: [] };
        }
      }

      function isValidCell(cellId) {
        return /^[A-J][1-9]|J10$/.test(cellId);
      }

      function getCellReferences(formula) {
        const matches = formula.match(/[A-Za-z][0-9]+/g) || [];
        const refs = new Set();
        for (const ref of matches) {
          const col = ref.charAt(0).toUpperCase();
          let row;
          try { row = parseInt(ref.slice(1), 10); } catch (e) { continue; }
          if (col >= 'A' && col <= 'J' && row >= 1 && row <= 10) {
            refs.add(col + row);
          }
        }
        return Array.from(refs);
      }

      function updateDependencies(cellId, newDeps) {
        const oldDeps = dependencyGraph[cellId].dependencies;
        for (const dep of oldDeps) {
          const index = dependencyGraph[dep].dependents.indexOf(cellId);
          if (index !== -1) { dependencyGraph[dep].dependents.splice(index, 1); }
        }
        for (const dep of newDeps) {
          if (!dependencyGraph[dep].dependents.includes(cellId)) {
            dependencyGraph[dep].dependents.push(cellId);
          }
        }
        dependencyGraph[cellId].dependencies = newDeps;
      }

      function evaluateCell(cellId, currentEvaluating = new Set()) {
        if (currentEvaluating.has(cellId)) {
          setComputedValue(cellId, '#CYCLE', '#CYCLE');
          return;
        }
        currentEvaluating.add(cellId);

        const cellData = cells[cellId];
        let value, display;

        try {
          const raw = cellData.raw;
          if (raw.startsWith('=')) {
            const formulaStr = raw.slice(1).trim();
            const dependencies = getCellReferences(formulaStr);
            for (const dep of dependencies) {
              if (!isValidCell(dep)) { throw new Error('Invalid reference'); }
            }

            updateDependencies(cellId, dependencies);

            let expr = formulaStr;
            for (const dep of dependencies) {
              evaluateCell(dep, currentEvaluating);
              const depVal = cells[dep].value;
              if (depVal === '#CYCLE' || depVal === '#ERR') { throw new Error('Cycle or error'); }
              expr = expr.replace(new RegExp(dep, 'g'), depVal.toString());
            }

            value = eval(expr);
            display = value;
          } else if (raw === '') {
            value = 0;
            display = '';
          } else if (!isNaN(raw)) {
            value = Number(raw);
            display = raw;
          } else {
            value = 0;
            display = raw;
          }
        } catch (e) {
          value = '#ERR';
          display = '#ERR';
        }

        setComputedValue(cellId, value, display);

        currentEvaluating.delete(cellId);

        for (const dependent of dependencyGraph[cellId].dependents) {
          evaluateCell(dependent, new Set(currentEvaluating));
        }
      }

      function setComputedValue(cellId, value, display) {
        const cellData = cells[cellId];
        cellData.value = value;
        cellData.displayValue = display;

        const input = document.getElementById('cell-' + cellId);
        if (input && !input.matches(':focus')) {
          input.value = display === '' ? '' : String(display);
        }
      }

      document.querySelectorAll('#spreadsheet input').forEach(input => {
        const idMatch = input.id.match(/cell-([A-J][1-9]|J10)/);
        if (!idMatch) return;
        const cellId = idMatch[1];

        let isEditing = false;

        input.addEventListener('focus', () => {
          isEditing = true;
          const cellData = cells[cellId];
          input.value = cellData.raw || '';
        });

        input.addEventListener('blur', () => {
          isEditing = false;
          const newValue = input.value.trim();
          if (newValue === '') { cells[cellId].raw = ''; } else { cells[cellId].raw = newValue; }
          evaluateCell(cellId);
        });

        input.addEventListener('keydown', e => {
          if (e.key === 'Enter') {
            e.preventDefault();
            input.blur();
          }
        });
      });

      document.getElementById('export').addEventListener('click', () => {
        let csv = '';
        for (let row = 1; row <= 10; row++) {
          const rowData = [];
          for (let col of 'ABCDEFGHIJ') {
            const cellId = `${col}${row}`;
            rowData.push(cells[cellId].value !== undefined ? cells[cellId].value : '');
          }
          csv += rowData.join(',') + '\n';
        }
        document.getElementById('csv').value = csv;
      });

      window.sheet = {
        set(id, value) {
          const cellIdMatch = id.match(/([A-J][1-9]|J10)/);
          if (!cellIdMatch) return;
          const cellId = cellIdMatch[1];
          const input = document.getElementById('cell-' + cellId);
          if (input) {
            input.value = value;
            input.dispatchEvent(new Event('blur'));
          }
        },
        get(id) {
          const cellIdMatch = id.match(/([A-J][1-9]|J10)/);
          if (!cellIdMatch) return '';
          const cellId = cellIdMatch[1];
          return cells[cellId].displayValue || '';
        },
        raw(id) {
          const cellIdMatch = id.match(/([A-J][1-9]|J10)/);
          if (!cellIdMatch) return '';
          const cellId = cellIdMatch[1];
          return cells[cellId].raw || '';
        }
      };

      for (let col of 'ABCDEFGHIJ') {
        for (let row = 1; row <= 10; row++) {
          evaluateCell(`${col}${row}`);
        }
      }
    });
  </script>
</body>
</html>

